func seedThreadFilterStore(t *testing.T, home string) {
	t.Helper()
	db, err := store.Open(filepath.Join(home, ".local", "share", "superhuman-pp-cli", "data.db"))
	if err != nil {
		t.Fatalf("open store: %v", err)
	}
	defer db.Close()
	if _, err := db.UpsertGmailMessages(t.Context(), []store.StoredMessage{
		{ID: "m1", ThreadID: "t1", AccountEmail: "user@example.com", LabelIDs: []string{"SENT", "Pitch"}, From: "user@example.com", To: "alice@example.com", Subject: "A", InternalDate: 300},
		{ID: "m2", ThreadID: "t2", AccountEmail: "user@example.com", LabelIDs: []string{"SENT"}, From: "user@example.com", To: "bob@example.com", Subject: "B", InternalDate: 200},
	}); err != nil {
		t.Fatalf("upsert: %v", err)
	}
}

func TestThreadsListParticipantsFileAndLabel(t *testing.T) {
	home := t.TempDir()
	t.Setenv("HOME", home)
	seedThreadFilterStore(t, home)
	configPath, tokenStorePath := withConfigPath(t)
	seedSendStore(t, tokenStorePath, "user@example.com", "gid-001")
	writeConfigPointingAt(t, configPath, "http://unused", "user@example.com")
	participantsPath := filepath.Join(t.TempDir(), "participants.txt")
	if err := os.WriteFile(participantsPath, []byte("alice@example.com\n"), 0o600); err != nil {
		t.Fatalf("write participants: %v", err)
	}

	stdout, _, err := executeCmd(t, "--config", configPath, "--json", "threads", "list", "--type", "sent", "--label", "Pitch", "--participants-file", participantsPath)
	if err != nil {
		t.Fatalf("threads list filters: %v", err)
	}
	var env map[string]any
	if err := json.Unmarshal([]byte(stdout), &env); err != nil {
		t.Fatalf("decode output: %v\n%s", err, stdout)
	}
	threads := env["threads"].([]any)
	if len(threads) != 1 || !strings.Contains(stdout, "t1") || strings.Contains(stdout, "t2") {
		t.Fatalf("filtered threads wrong: %s", stdout)
	}
}

